<?php
 namespace FilesManager\Traits; use FilesManager\Validator; trait Validatable { protected function validateRequired($value, string $fieldName): void { $isEmpty = $value === null || (is_string($value) && trim($value) === '') || (is_array($value) && empty($value)); if ($isEmpty) { throw new \Exception(sprintf('%s é obrigatório', $fieldName)); } } protected function validatePath(string $path, string $basePath): string|false { return Validator::validatePath($path, $basePath); } protected function validateFileExtension(string $filename, array $allowed = []): bool { return Validator::validateExtension($filename, $allowed); } protected function validateMimeType(string $filePath, array $allowed = []): bool { return Validator::validateMimeType($filePath, $allowed); } protected function sanitizeFilename(string $filename): string { $filename = trim($filename); $filename = str_replace(['\\', '/', ':', '*', '?', '"', '<', '>', '|'], '', $filename); $filename = preg_replace('/\s+/', ' ', $filename) ?? $filename; if (strlen($filename) > 255) { $filename = substr($filename, 0, 255); } return $filename; } } 